const items = $input.all();
const critiqueOutput = items[0].json.output || items[0].json.text || 'No refinement suggestions available';
const ctx = $('Check Iteration Limit').first().json;

return [{
  json: {
    symbol: ctx.symbol,
    strategy_type: ctx.strategy_type,
    constraints: ctx.constraints,
    iteration: ctx.iteration,
    max_iterations: ctx.max_iterations,
    refinement_notes: critiqueOutput,
    status: 'refining'
  }
}];

const ctx = $('Check Iteration Limit').first().json;

return [{
  json: {
    success: false,
    status: 'rejected_max_iterations',
    strategy_type: ctx.strategy_type,
    symbol: ctx.symbol,
    iterations_used: ctx.iteration,
    max_iterations: ctx.max_iterations,
    last_tier: ctx.last_tier,
    last_metrics: ctx.last_metrics,
    rejection_reason: ctx.rejection_reason,
    message: `Strategy generation failed after ${ctx.iteration} iterations. Last tier: ${ctx.last_tier}`
  }
}];

const items = $input.all();
const data = items[0].json;

console.log('COMPILER GATE: Strategy failed compilation');
console.log('Errors:', JSON.stringify(data.errors || data.message || 'Unknown'));

return [{
  json: {
    status: 'compilation_failed',
    errors: data.errors || data.message || 'Unknown compiler error',
    skipped_backtest: true,
    timestamp: new Date().toISOString()
  }
}];

